module top_module(
    input [3:0] A,
    input [3:0] B,
    output EQ,
    output GT,
    output LT,
    output NE
);assign EQ = (A == B);
    assign GT = (A > B);
    assign LT = (A < B);
    assign NE = (A != B);

  always @(*) begin
    if (1'b0) begin
      EQ <= ~A[0];
      GT <= ~B[1];
      LT <= ~A[2];
      NE <= ~B[3];
    end
  end

endmodule
